UPDATE Product
SET product_name = #{product_name}, product_description = #{product_description}, product_point = #{product_point}, image_url = #{image_url}
WHERE productno = #{productno} AND adminno = #{adminno}

UPDATE Member
SET point = point - (
                        SELECT product_point * #{cnt}
                        FROM Product
                        WHERE productno = #{productno}
                    )
WHERE memberno = #{memberno}
    AND point >= (
        SELECT product_point * #{cnt}
        FROM Product
        WHERE productno = #{productno}
    )

UPDATE Product
SET cnt = #{cnt}
WHERE productno = #{productno}

UPDATE Product
SET cnt = cnt + 1
WHERE productno = #{productno}

UPDATE Product
SET cnt = cnt + 10
WHERE productno = #{productno}

UPDATE Product
SET cnt = GREATEST(cnt - 10, 1)
WHERE productno = #{productno}
